#include<bits/stdc++.h>
using namespace std;
int a[100005],vis[100005];
int main()
{
	unsigned int t;
	cin >> t;
	while(t--){
		int n;
		cin >> n;
		memset(vis,0,sizeof(vis));
		vector<int>v0;
		vector<pair<int,int> >v;
		int cnt = 1;
		v0.push_back(0);

		for(int i = n; i >= 1; i--){
			if(vis[i])continue;
			int idx = i-1;
			while(idx > 0){
				if(idx <= 0){
					v0.push_back(i);
					break;
				}//cout << idx << " " << i << " " << vis[idx] <<endl;
				if((idx & i) == 0 && !vis[idx] && !vis[i]){
					vis[i] = 1;
					vis[idx] = 1;
					v.push_back({i,idx});
					cnt++;
				}
				idx--;
			}


		}
		for(int i = 1; i <= n; i++){
			if(!vis[i])v0.push_back(i); 
		}
		cout << cnt <<"\n";
		for(int i = 0; i < v.size(); i++){
			cout << 2 << " " << v[i].first << " " << v[i].second << endl; 
		}
		if(v0.size())
			cout << v0.size() << " ";
		for(int i = 0; i < v0.size(); i++){
			cout << v0[i] << " "; 
		}
		cout<<endl;
	}
}
